module RefModule(
  clk,
  reset,
  enable,
  out
);input wire clk;
input wire reset;
input wire enable;
output reg [3:0] out;

  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt) begin
  if (reset) begin
    out <= 4'b0000;
  end else if (enable) begin
    out <= out + 1;
  end
end

endmodule
